<!--/** * @version 0.9 * @author Kees Schepers <kees.schepers@scooterbase.net>  * @package SB Framework * @copyright ScooterBase.net */   /** * Exception which will be thrown when something happends with the menu building  */class Site_Menu_Exception extends Exception {}/** * Drawes and takes care for the whole menu, but not the contents * @version 0.9 *///class Site_Menu {        /**     * Map with items first key is the parentid     *     * @var array     */  //  private $items;    /**     * HTML id of the first <ul> tag     *     * @var string     */  //  private $elementId;    /**     * Constructor, construct a menu     *     * @param string $elementId id of the root UL element     * @return void     */    public function __construct($elementId) {        $this->items = array();        if(preg_match('/^[a-z]{1,}[a-z0-9]*/i',$elementId)) {            $this->elementId = $elementId;        } else {            throw new Site_Menu_Exception('Element id ('.$elementId.') is not XHTML valid');        }    }    /**     * Add an list item     *     * @param Site_Menu_Item $item     * @return void     */    public function addItem(Site_Menu_Item $item) {                $this->items[$item->parent][] = $item;    }    /**     * Recursively loop all items     *     * @param string $parent     * @return string HTML contents     */    private function getItems($parent) {        $str = '';                foreach ($this->items[$parent] as $item) {            $str .= '<li><a '.(!is_null($item->class) ? 'class="'.$item->class.'"' : '').' href="'.$item->href.'" title="'.$item->title.'">'.$item->title.'</a>';                                    if(array_key_exists($item->title,$this->items)) {                                $str .= '<ul>';                $str .= $this->getItems($item->title);                $str .= '</ul>';            }                        $str .= '</li>';        }                return $str;    }    public function getHTML() {        return '<ul id="'.$this->elementId.'">'.$this->getItems('root').'</ul>';    }}/** * Just an single menu item (link) * */class Site_Menu_Item {    /**     * An map with properties (href, class, title, etc)     *     * @var array     */    private $properties;    /**     * Create a new menu item     *     * @param string $title     * @param string $href     * @param string $parent     * @return void     */    public function __construct($title,$href,$parent='root') {        $this->properties = array();                $this->__set('title',$title);        $this->__set('href',$href);        $this->__set('parent',$parent);        $this->__set('class',null);                    }    /**     * Get the properties of an menu element     *     * @param string $key     * @return mixed     */    public function __get($key) {        if(array_key_exists($key,$this->properties)) {            return $this->properties[$key];        } else {            throw new Site_Menu_Exception('Cannot get property '.$key);        }    }    /**     * Set the properties of an menu element     *     * @param string $key     * @param mixed $value     * @return boolean     */    public function __set($key,$value) {        switch ($key) {            case 'href' :            case 'title' :            case 'parent' :            case 'class' :                $this->properties[$key] = $value;                return true;            default :                throw new Site_Menu_Exception('Cannot set property '.$key);                return false;        }    }}--><html><head><title>Untitled Document</title><meta http-equiv="Content-Type" content="text/html; charset=iso-8859-1"><style type="text/css"><!--#menu {  margin:0;   padding:0;   width:45em;  height:8.5em;  overflow:hidden;   background:#000;  }#menu li {  display:inline;  list-style-type:none;   }#menu li a {  display:block;  float:left;  text-decoration:none;   margin:0;   }#menu li a img {  opacity:0.7;  margin:0.5em;  border:0;  float:left;  }#menu li a span {  display:none;   }#menu li a:hover {  background:#000;  }#menu li a:hover img {  opacity:1;  }#menu li a:hover span {  width:11em;  color:#aaa;  display:block;   cursor:pointer;  float:left;  }#menu .h2 {  margin:0 5px;   padding:0;   color:#fc0;   font-variant:small-caps;   font-size:1.25em;   border:0;  }#menu .h3 {  margin:0 5px;   padding:0;   font-size:1.1em;   color:#0aa;  }.outer {  background:transparent;   font-size:0.9em;  }--></style></head><body><div class="outer">  <ul id="menu">   <li>    <a href="#nogo">     <img src="../img/cezanne.jpg" alt="painting" title="painting" />     <span>      <b class="h2">Paul Cézanne</b><br />      <b class="h3">(1839-1906)</b><br />      One of the great forerunners of modern painting.     </span>    </a>   </li>   <li>    <a href="#nogo">     <img src="../img/matisse.jpg" alt="painting" title="painting" />     <span>      <b class="h2">Henri Matisse</b><br />      <b class="h3">(1869-1954)</b><br />      Became a leader in many art circles.     </span>    </a>   </li>   <li>    <a href="#nogo">     <img src="../img/turner.jpg" alt="painting" title="painting" />     <span>      <b class="h2">William Turner</b><br />      <b class="h3">(1775-1851)</b><br />      Unrivaled in the virtuosity of his painting of light.     </span>    </a>   </li>   <li>    <a href="#nogo">     <img src="../img/monet.jpg" alt="painting" title="painting" />     <span>      <b class="h2">Claude Monet</b><br />      <b class="h3">(1840-1926)</b><br />      Never abandoned his Impressionist painting style.     </span>    </a>   </li>  </ul></div></body></html>